import asyncio
import json
import uuid
from dataclasses import dataclass, field
from typing import Dict, Optional, Set, Any
import websockets
from websockets.server import WebSocketServerProtocol

@dataclass
class Item:
    item_id: str
    name: str
    owner_id: str

@dataclass
class Player:
    player_id: str
    username: str
    websocket: Optional[WebSocketServerProtocol] = None
    inventory: Set[str] = field(default_factory=set)

class GameState:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.lock = asyncio.Lock()

    async def register(self, websocket: WebSocketServerProtocol, username: str) -> str:
        async with self.lock:
            player_id = str(uuid.uuid4())
            self.players[player_id] = Player(player_id=player_id, username=username, websocket=websocket)
            return player_id

    async def unregister(self, player_id: str):
        async with self.lock:
            player = self.players.get(player_id)
            if player:
                player.websocket = None

    async def create_item(self, owner_id: str, name: str) -> str:
        async with self.lock:
            item_id = str(uuid.uuid4())
            item = Item(item_id=item_id, name=name, owner_id=owner_id)
            self.items[item_id] = item
            if owner_id in self.players:
                self.players[owner_id].inventory.add(item_id)
            return item_id

    async def transfer_item(self, from_player_id: str, to_player_id: str, item_id: str) -> bool:
        async with self.lock:
            item = self.items.get(item_id)
            from_player = self.players.get(from_player_id)
            to_player = self.players.get(to_player_id)

            if not item or not from_player or not to_player:
                return False
            if item.owner_id != from_player_id:
                return False
            if item_id not in from_player.inventory:
                return False

            from_player.inventory.remove(item_id)
            to_player.inventory.add(item_id)
            item.owner_id = to_player_id
            return True

    async def get_inventory(self, player_id: str) -> Dict[str, Any]:
        async with self.lock:
            player = self.players.get(player_id)
            if not player:
                return {"error": "unknown player"}
            items = []
            for item_id in player.inventory:
                item = self.items.get(item_id)
                if item:
                    items.append({"item_id": item.item_id, "name": item.name, "owner_id": item.owner_id})
            return {"player_id": player_id, "inventory": items}

state = GameState()

async def send_json(ws: WebSocketServerProtocol, payload: dict):
    await ws.send(json.dumps(payload))

async def handler(websocket: WebSocketServerProtocol):
    player_id: Optional[str] = None
    try:
        async for message in websocket:
            try:
                data = json.loads(message)
            except json.JSONDecodeError:
                await send_json(websocket, {"ok": False, "error": "invalid json"})
                continue

            action = data.get("action")

            if action == "register":
                username = str(data.get("username", "")).strip()
                if not username:
                    await send_json(websocket, {"ok": False, "error": "username required"})
                    continue
                player_id = await state.register(websocket, username)
                await send_json(websocket, {"ok": True, "action": "register", "player_id": player_id})

            elif action == "create_item":
                if not player_id:
                    await send_json(websocket, {"ok": False, "error": "not registered"})
                    continue
                name = str(data.get("name", "")).strip()
                if not name:
                    await send_json(websocket, {"ok": False, "error": "item name required"})
                    continue
                item_id = await state.create_item(player_id, name)
                await send_json(websocket, {"ok": True, "action": "create_item", "item_id": item_id})

            elif action == "transfer_item":
                if not player_id:
                    await send_json(websocket, {"ok": False, "error": "not registered"})
                    continue
                to_player_id = str(data.get("to_player_id", "")).strip()
                item_id = str(data.get("item_id", "")).strip()
                if not to_player_id or not item_id:
                    await send_json(websocket, {"ok": False, "error": "to_player_id and item_id required"})
                    continue
                success = await state.transfer_item(player_id, to_player_id, item_id)
                await send_json(websocket, {"ok": success, "action": "transfer_item", "item_id": item_id, "to_player_id": to_player_id})

            elif action == "inventory":
                if not player_id:
                    await send_json(websocket, {"ok": False, "error": "not registered"})
                    continue
                inv = await state.get_inventory(player_id)
                await send_json(websocket, {"ok": True, "action": "inventory", "data": inv})

            else:
                await send_json(websocket, {"ok": False, "error": "unknown action"})
    except websockets.ConnectionClosed:
        pass
    finally:
        if player_id:
            await state.unregister(player_id)

async def main():
    async with websockets.serve(handler, "0.0.0.0", 8765, ping_interval=20, ping_timeout=20):
        await asyncio.Future()

if __name__ == "__main__":
    asyncio.run(main())